  ARRAY['/Nagano/photo_16_2026-06-27_13-58-51.jpg', '/Nagano/photo_17_2026-06-27_13-58-51.jpg'],
  '[{"title": "Сува Тайся — древнее синтоистское святилище", "text": "Путешествие начинается с легендарного комплекса Сува Тайся, история которого насчитывает более 1200 лет. Святилище посвящено божествам природы, гор и озёр; раз в шесть лет здесь проходит знаменитый фестиваль Онбасира.", "image_query": "Suwa Taisha shrine Nagano", "image_url": "/Nagano/suwa_01.jpg"}, {"title": "Озеро Сува", "text": "Небольшая остановка у живописного озера в окружении гор Японских Альп — прекрасное место для отдыха и красивых фотографий.", "image_query": "Lake Suwa Nagano mountains", "image_url": "/Nagano/suwalake_01.jpg"}, {"title": "Ishii Miso — старинная мисо-пивоварня", "text": "Семейная пивоварня, основанная в 1868 году. Уже более 150 лет здесь делают трёхлетнее мисо естественного брожения в огромных кедровых бочках. Небольшая экскурсия и дегустация фирменных блюд Синсю.", "image_query": "Japanese miso brewery cedar barrels", "image_url": "/Nagano/photo_8_2026-06-27_13-58-51.jpg"}, {"title": "Замок Мацумото", "text": "Один из двенадцати оригинальных замков Японии, сохранившихся с эпохи самураев. Построенный более 400 лет назад, он известен как «Замок Чёрного Ворона» благодаря чёрному фасаду. Древние интерьеры, оборонительные сооружения и виды на Японские Альпы.", "image_query": "Matsumoto Castle black crow", "image_url": "/Nagano/photo_4_2026-06-27_13-58-51.jpg"}, {"title": "Daio Wasabi Farm (по желанию)", "text": "Одна из крупнейших васаби-ферм Японии. Кристально чистая горная вода, живописные каналы, необычные блюда с васаби и знаменитое мороженое.", "image_query": "Daio Wasabi Farm Nagano canals", "image_url": "/Nagano/wasabi_01.jpg"}]'::jsonb,
