  '[{"title": "День 1 · Дзэнкодзи", "text": "Один из древнейших буддийских храмов Японии, основанный почти 1400 лет назад. Под главным залом — знаменитый тёмный коридор, символ пути к просветлению. Прогулка по старинной торговой улице Накамисэ.", "image_query": "Zenkoji temple Nagano", "image_url": "/Nagano/photo_1_2026-06-27_13-58-51.jpg"}, {"title": "День 2 · Парк снежных обезьян Дзигокудани", "text": "Прогулка по лесной тропе к знаменитым японским макакам, которые круглый год отдыхают в природных горячих источниках.", "image_query": "Jigokudani snow monkeys hot spring", "image_url": "/Nagano/photo_12_2026-06-27_13-58-51.jpg"}, {"title": "День 2 · Обусэ и наследие Хокусая", "text": "Городок, сохранивший атмосферу эпохи Эдо: каштановые сладости, музей Кацусики Хокусая и грандиозная потолочная роспись «Феникс» в храме Гансёин.", "image_query": "Obuse town Hokusai Nagano", "image_url": "/Nagano/photo_5_2026-06-27_13-58-51.jpg"}, {"title": "День 3 · Святилище Тогакуси", "text": "Одно из самых загадочных святилищ Японии, связанное с мифом о богине солнца Аматэрасу. Аллея многовековых кедров — одна из красивейших в стране.", "image_query": "Togakushi shrine cedar avenue", "image_url": "/Nagano/photo_2_2026-06-27_13-58-51.jpg"}, {"title": "День 3 · Обед на мисо-пивоварне Ishii Miso", "text": "Семейная пивоварня 1868 года: трёхлетнее мисо в кедровых бочках и фирменный обед с блюдами кухни Синсю.", "image_query": "Japanese miso brewery cedar barrels", "image_url": "/Nagano/photo_8_2026-06-27_13-58-51.jpg"}, {"title": "День 3 · Замок Мацумото", "text": "«Замок Чёрного Ворона» — один из двенадцати оригинальных замков Японии и национальное сокровище страны.", "image_query": "Matsumoto Castle black crow", "image_url": "/Nagano/photo_11_2026-06-27_13-58-51.jpg"}, {"title": "День 3–4 · Кусацу Онсэн", "text": "Один из трёх самых известных онсэн-курортов Японии с тысячелетней историей. Заселение в традиционный рёкан, ужин кайсэки, термальные источники.", "image_query": "Kusatsu Onsen ryokan", "image_url": "/Nagano/kusatsu_01.jpg"}, {"title": "День 4 · Юбатакэ и шоу Юмоми", "text": "Главный символ Кусацу — деревянный комплекс Юбатакэ; традиционное шоу охлаждения горячей воды большими деревянными лопатками под народные песни.", "image_query": "Kusatsu Onsen Yumomi show", "image_url": "/Nagano/photo_6_2026-06-27_13-58-51.jpg"}]'::jsonb,
  '{}'::jsonb
